import java.util.regex.Matcher;
import java.util.regex.Pattern;

public int countCode(String str) {
    Pattern pattern = Pattern.compile("co.e");
    Matcher matcher = pattern.matcher(str);

    int count = 0;
    while (matcher.find()) {
        count++;
    }

    return count;
}
```

