public int centeredAverage(int[] nums) {
    // Find the minimum and maximum values excluding duplicates
    int min = Integer.MAX_VALUE;
    int max = Integer.MIN_VALUE;
    Set<Integer> set = new HashSet<>();
    for (int num : nums) {
        if (!set.contains(num)) {
            min = Math.min(min, num);
            max = Math.max(max, num);
            set.add(num);
        }
    }

    // Calculate the sum of values excluding min and max
    int sum = 0;
    int count = 0;
    for (int num : nums) {
        if (num != min && num != max) {
            sum += num;
            count++;
        }
    }

    // Calculate centered average
    return sum / count;
}
